using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removes "Discriminator" property from non-hierarchical containers.
            // Existing documents have "Discriminator": "Blog" — must opt back in.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Blog");

            // Breaking change 2: EF 9 uses only the raw key for "id" (e.g. "1").
            // Existing documents have id = "Blog|1". Preserve that format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: EF 9 no longer supports HasIndex on Cosmos.
            // Cosmos uses server-side indexing policies, not EF-managed indexes.
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

