class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: EF 9 uses sync-over-async for Cosmos by default
        // which may deadlock in some hosting models. Prefer async APIs.
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();

        // Breaking change 5: Raw SQL using "Discriminator" still works only because
        // we opted back in via HasDiscriminator(). Without that, EF 9 would no longer
        // emit/read the property and queries like:
        //   SELECT * FROM c WHERE c.Discriminator = 'Blog'
        // would return zero results.
    }
}

